<?phpnamespace App\Repository;use App\Entity\Expertise;use Doctrine\Bundle\DoctrineBundle\Repository\ServiceEntityRepository;use Doctrine\ORM\NonUniqueResultException;use Doctrine\ORM\NoResultException;use Doctrine\ORM\QueryBuilder;use Doctrine\Persistence\ManagerRegistry;/** * @method Expertise|null find($id, $lockMode = null, $lockVersion = null) * @method Expertise|null findOneBy(array $criteria, array $orderBy = null) * @method Expertise[]    findAll() * @method Expertise[]    findBy(array $criteria, array $orderBy = null, $limit = null, $offset = null) */class ExpertiseRepository extends ServiceEntityRepository{    public function __construct(ManagerRegistry $registry)    {        parent::__construct($registry, Expertise::class);    }    /**     * @param string $sortType     * @param $sortDesc     * @return float|int|mixed|string     */    public function getExpertisesSortBy(string $sortType, $sortDesc = null)    {        $array = $this->getProperty($sortType, $sortDesc);        return $this->createQueryBuilder('e')            ->leftJoin('e.bienClient', 'b')            ->leftJoin('b.Quartier', 'q')            ->leftJoin('b.kohUtilisateur', 'u')            ->leftJoin('e.dossierMbeyan', 'd')            ->leftJoin('e.clientStructure', 'clientStructure')            ->leftJoin('e.typeAcquisition', 'typeAcquisition')            ->leftJoin('e.typeDocumentPropriete', 'typeDocument')            ->leftJoin('e.typeBien', 'typeBien')            ->leftJoin('e.typeUsageBien', 'typeUsage')            ->orderBy('' . $array[0]['property'], '' . $array[0]['type'])            ->getQuery()            ->getResult();    }    /**     * @param array $critere     * @return int|mixed|string     */    public function getExpertiseByCritere(array $critere)    {        $query = $this->createQueryBuilder('e')            ->leftJoin('e.bienClient', 'b')            ->leftJoin('b.kohUtilisateur', 'u');        if (array_key_exists('typeClient', $critere)) {            $query->leftJoin('u.typeCompte', 'typeCompte');            $query->andWhere('typeCompte.id = :typeCompteID')                ->setParameter('typeCompteID', $critere['typeClient']);        }        if (array_key_exists('client', $critere)) {            $query->andWhere('u.id = :userID')                ->setParameter('userID', $critere['client']);        }        $query = $this->getQueryWithCritere($query, $critere);        return $query->getQuery()->getResult();    }    /**     * @param string $sortType     * @param $sortDesc     * @return string[][]     */    public function getProperty(string $sortType, $sortDesc): array    {        if ($sortType === 'quartier') {            $property = 'q.name';            $type = 'ASC';            if ($sortDesc) {                $type = 'DESC';            }        } elseif ($sortType === 'tf') {            $property = 'b.numeroDocument';            $type = 'ASC';            if ($sortDesc) {                $type = 'DESC';            }        } elseif ($sortType === 'expertise') {            $property = 'e.numeroExpertise';            $type = 'ASC';            if ($sortDesc) {                $type = 'DESC';            }        } elseif ($sortType === 'client') {            $property = 'u.firstName';            $type = 'ASC';            if ($sortDesc) {                $type = 'DESC';            }        } elseif ($sortType === 'price') {            $property = 'e.lastEvaluationPrice';            $type = 'ASC';            if ($sortDesc) {                $type = 'DESC';            }        } elseif ($sortType === 'numero_mbeyan') {            $property = 'd.numeroDossier';            $type = 'ASC';            if ($sortDesc) {                $type = 'DESC';            }        } elseif ($sortType === 'proprietaire') {            $property = 'clientStructure.name';            $type = 'ASC';            if ($sortDesc) {                $type = 'DESC';            }        } elseif ($sortType === 'type_acquisition') {            $property = 'typeAcquisition.name';            $type = 'ASC';            if ($sortDesc) {                $type = 'DESC';            }        } elseif ($sortType === 'type_document') {            $property = 'typeDocument.name';            $type = 'ASC';            if ($sortDesc) {                $type = 'DESC';            }        } elseif ($sortType === 'type_bien') {            $property = 'typeBien.name';            $type = 'ASC';            if ($sortDesc) {                $type = 'DESC';            }        } elseif ($sortType === 'type_usage') {            $property = 'typeUsage.name';            $type = 'ASC';            if ($sortDesc) {                $type = 'DESC';            }        } elseif ($sortType === 'superficie') {            $property = 'e.superficie';            $type = 'ASC';            if ($sortDesc) {                $type = 'DESC';            }        } elseif ($sortType === 'derniere_expertise') {            $property = 'e.dateEvaluation';            $type = 'ASC';            if ($sortDesc) {                $type = 'DESC';            }        } elseif ($sortType === 'prochaine_expertise') {            $property = 'e.dateNextEvaluation';            $type = 'ASC';            if ($sortDesc) {                $type = 'DESC';            }        } elseif ($sortType === 'created_at') {            $property = 'e.createdAt';            $type = 'ASC';            if ($sortDesc) {                $type = 'DESC';            }        } elseif ($sortType === 'updated_at') {            $property = 'e.updatedAt';            $type = 'ASC';            if ($sortDesc) {                $type = 'DESC';            }        } elseif ($sortType === 'cercle') {            $property = 'cercle.name';            $type = 'ASC';            if ($sortDesc) {                $type = 'DESC';            }        } elseif ($sortType === 'region') {            $property = 'region.name';            $type = 'ASC';            if ($sortDesc) {                $type = 'DESC';            }        } else {            $property = 'b.id';            $type = 'DESC';        }        return array(['property' => $property, 'type' => $type]);    }    /**     * @param QueryBuilder $query     * @param $critere     * @return QueryBuilder     */    public function getQueryWithCritere(QueryBuilder $query, $critere): QueryBuilder    {        if (array_key_exists('numeroCompteClientStructure', $critere)) {            $numeroCompte = $critere['numeroCompteClientStructure'];            $query->leftJoin('e.clientStructure', 'clientStructure')                ->andWhere('clientStructure.name LIKE :numeroCompte')                ->setParameter('numeroCompte', '%' . $numeroCompte . '%');        }        if (array_key_exists('tf', $critere)) {            $tf = $critere['tf'];            $query->andWhere('b.numeroDocument LIKE :numeroDoc')                ->setParameter('numeroDoc', '%' . $tf . '%');        }        if (array_key_exists('quartierFilter', $critere)) {            $query->leftJoin('b.Quartier', 'quartier');            $query->andWhere('quartier.id =:quartier')                ->setParameter('quartier', $critere['quartierFilter']);        }        if (array_key_exists('regionFilter', $critere)) {            $query->leftJoin('b.Quartier', 'quartier1')                ->leftJoin('quartier1.commune', 'commune1')                ->leftJoin('commune1.cercle', 'cercle1')                ->leftJoin('cercle1.region', 'region1')                ->andWhere('region1.id = :region1')                ->setParameter('region1', $critere['regionFilter']);        }        if (array_key_exists('cercleFilter', $critere)) {            $query->leftJoin('b.Quartier', 'quartier2')                ->leftJoin('quartier2.commune', 'commune2')                ->leftJoin('commune2.cercle', 'cercle2')                ->andWhere('cercle2.id = :cercle2')                ->setParameter('cercle2', $critere['cercleFilter']);        }        if (array_key_exists('numeroExpertise', $critere)) {            $query->andWhere('e.numeroExpertise LIKE :numeroExpertise')                ->setParameter('numeroExpertise', '%' . $critere['numeroExpertise'] . '%');        }        if (array_key_exists('numeroMbeyan', $critere)) {            $query->leftJoin('e.dossierMbeyan', 'dossier_mbeyan')                ->andWhere('dossier_mbeyan.numeroDossier LIKE :numeroMbeyan')                ->setParameter('numeroMbeyan', '%' . $critere['numeroMbeyan'] . '%');        }        if (array_key_exists('dateFinDation', $critere) && array_key_exists('dateDebutDation', $critere)) {            $dateInf = date($critere['dateDebutDation']);            $dateSup = date($critere['dateFinDation']);            $query->andWhere('e.dateFinDation BETWEEN :dateInf and :dateSup')                ->setParameter('dateInf', $dateInf)                ->setParameter('dateSup', $dateSup);        }        if (array_key_exists('dateFinImmobilisation', $critere) && array_key_exists('dateDebutImmobilisation', $critere)) {            $dateInf = date($critere['dateDebutImmobilisation']);            $dateSup = date($critere['dateFinImmobilisation']);            $query->andWhere('e.dateSortieImmobilisation BETWEEN :dateInf and :dateSup')                ->setParameter('dateInf', $dateInf)                ->setParameter('dateSup', $dateSup);        }        if (array_key_exists('typeDocument', $critere)) {            $query->leftJoin('e.typeDocumentPropriete', 'typedocumentpropriete');            $query->andWhere('typedocumentpropriete.id = :typeDocumentID')                ->setParameter('typeDocumentID', $critere['typeDocument']);        }        if (array_key_exists('typeAcquisition', $critere)) {            $query->leftJoin('e.typeAcquisition', 'typeAcquisition');            $query->andWhere('typeAcquisition.id IN (:typeAcquisitionID)')                ->setParameter('typeAcquisitionID', $critere['typeAcquisition']);        }        if (array_key_exists('typeUsageBien', $critere)) {            $query->leftJoin('e.typeUsageBien', 'type_usage_bien')                ->andWhere('type_usage_bien.id = :typeUsageBienId')                ->setParameter('typeUsageBienId', $critere['typeUsageBien']);        }        if (array_key_exists('typeBien', $critere)) {            $query->leftJoin('e.typeBien', 'type_bien')                ->andWhere('type_bien.id = :typeBienId')                ->setParameter('typeBienId', $critere['typeBien']);        }        if (array_key_exists('prixEstimationInf', $critere) && array_key_exists('prixEstimationSup', $critere)) {            $prixInf = $critere['prixEstimationInf'];            $prixSup = $critere['prixEstimationSup'];            $query->andWhere('e.lastEvaluationPrice >= :prixInf')                ->andWhere('e.lastEvaluationPrice <= :prixSup')                ->setParameter('prixInf', $prixInf)                ->setParameter('prixSup', $prixSup);        }        if (array_key_exists('dateInfLastEvaluation', $critere) && array_key_exists('dateSupLastEvaluation', $critere)) {            $dateInf = date($critere['dateInfLastEvaluation']);            $dateSup = date($critere['dateSupLastEvaluation']);            $query->andWhere('e.dateEvaluation BETWEEN :dateInf and :dateSup')                ->setParameter('dateInf', $dateInf)                ->setParameter('dateSup', $dateSup);        }        if (array_key_exists('dateInfNextEvaluation', $critere) && array_key_exists('dateSupNextEvaluation', $critere)) {            $dateInf1 = date($critere['dateInfNextEvaluation']);            $dateSup1 = date($critere['dateSupNextEvaluation']);            $query->andWhere('e.dateNextEvaluation BETWEEN :dateInf and :dateSup')                ->setParameter('dateInf', $dateInf1)                ->setParameter('dateSup', $dateSup1);        }        return $query;    }    /**     * @param String $ids     * @param $by     * @param $sortType     * @return float|int|mixed|string     */    public function getBienClientsByArrayId(string $ids, $by, $sortType)    {        $data = explode(',', $ids);        if ($sortType === 'ASC') {            $array = $this->getProperty($by, false);        } else {            $array = $this->getProperty($by, true);        }        return $this->createQueryBuilder('e')            ->leftJoin('e.bienClient', 'b')            ->leftJoin('b.Quartier', 'q')            ->leftJoin('q.commune', 'commune')            ->leftJoin('commune.cercle', 'cercle')            ->leftJoin('cercle.region', 'region')            ->leftJoin('b.kohUtilisateur', 'u')            ->leftJoin('e.dossierMbeyan', 'd')            ->leftJoin('e.clientStructure', 'clientStructure')            ->leftJoin('e.typeAcquisition', 'typeAcquisition')            ->leftJoin('e.typeDocumentPropriete', 'typeDocument')            ->leftJoin('e.typeBien', 'typeBien')            ->leftJoin('e.typeUsageBien', 'typeUsage')            ->where('e.id IN (:data)')            ->setParameter('data', array_values($data))            ->orderBy('' . $array[0]['property'], '' . $array[0]['type'])            ->getQuery()            ->getResult();    }    /**     * @param int $structureId     * @return mixed     * @throws NoResultException     * @throws NonUniqueResultException     */    public function countStructureExpertises(int $structureId)    {        return $this->createQueryBuilder('e')            ->leftJoin('e.bienClient', 'b')            ->leftJoin('b.kohUtilisateur', 'kohUtilisateur')            ->leftJoin('kohUtilisateur.structure', 'structure')            ->select('count(e.id)')            ->where('structure.id =:structureId')            ->setParameter('structureId', $structureId)            ->getQuery()->getSingleScalarResult();    }}